bool Assets::GetAssetData(const std::string& name, void*& ptr, size_t& size) {
    // Check if partition is valid and initialized
    if (!partition_valid_ || !checksum_valid_ || mmap_root_ == nullptr) {
        return false;
    }

    // Check if the asset exists in our assets map
    auto it = assets_.find(name);
    if (it == assets_.end()) {
        return false;
    }

    // Get the asset information
    const auto& asset = it->second;

    // Validate that the asset data is within bounds
    if (asset.offset + asset.size > partition_->size) {
        ESP_LOGE(TAG, "Asset %s data extends beyond partition bounds", name.c_str());
        return false;
    }

    // Set the output parameters
    ptr = const_cast<void*>(static_cast<const void*>(mmap_root_ + asset.offset));
    size = asset.size;

    // Validate asset integrity by checking magic number
    // Assuming the first 4 bytes of each asset contain a magic number
    uint32_t* magic_ptr = static_cast<uint32_t*>(ptr);
    uint32_t magic_number = *magic_ptr;

    // Check if magic number is valid (this depends on how assets are structured)
    // For now, we'll assume any non-zero magic number indicates valid asset
    // In practice, this would be specific to the asset format
    if (magic_number == 0) {
        ESP_LOGW(TAG, "Asset %s has invalid magic number", name.c_str());
        return false;
    }

    return true;
}

