esp_err_t Ota::CheckVersion() {
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "OTA URL is empty");
        return ESP_ERR_INVALID_ARG;
    }

    if (url.back() != '/') {
        url += "/";
    }
    url += "check-version";

    auto http = SetupHttp();

    // Prepare the request body with current version information
    cJSON *request_payload = cJSON_CreateObject();
    cJSON_AddStringToObject(request_payload, "device_id", SystemInfo::GetMacAddress().c_str());
    cJSON_AddStringToObject(request_payload, "client_id", Board::GetInstance().GetUuid());
    cJSON_AddStringToObject(request_payload, "current_version", esp_app_get_description()->version);

    if (has_serial_number_) {
        cJSON_AddStringToObject(request_payload, "serial_number", serial_number_.c_str());
    }

    auto json_str = cJSON_PrintUnformatted(request_payload);
    std::string data(json_str);
    cJSON_free(json_str);
    cJSON_Delete(request_payload);

    http->SetContent(std::move(data));

    if (!http->Open("POST", url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection for version check");
        return ESP_FAIL;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200) {
        ESP_LOGE(TAG, "Failed to check version, status code: %d", status_code);
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty()) {
        ESP_LOGE(TAG, "Empty response from version check endpoint");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Version check response: %s", response.c_str());

    // Parse JSON response
    cJSON *json = cJSON_Parse(response.c_str());
    if (json == NULL) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Check for activation challenge
    cJSON *activation_challenge = cJSON_GetObjectItemCaseSensitive(json, "activation_challenge");
    if (cJSON_IsString(activation_challenge) && (activation_challenge->valuestring != NULL)) {
        activation_challenge_ = std::string(activation_challenge->valuestring);
        has_activation_challenge_ = true;
        ESP_LOGI(TAG, "Received activation challenge: %s", activation_challenge_->c_str());
    }

    // Check for firmware URL
    cJSON *firmware_url = cJSON_GetObjectItemCaseSensitive(json, "firmware_url");
    if (cJSON_IsString(firmware_url) && (firmware_url->valuestring != NULL)) {
        firmware_url_ = std::string(firmware_url->valuestring);
        ESP_LOGI(TAG, "Firmware URL: %s", firmware_url_.c_str());
    }

    // Check for new version
    cJSON *new_version = cJSON_GetObjectItemCaseSensitive(json, "new_version");
    if (cJSON_IsString(new_version) && (new_version->valuestring != NULL)) {
        std::string new_version_str = std::string(new_version->valuestring);
        std::string current_version = std::string(esp_app_get_description()->version);

        if (IsNewVersionAvailable(current_version, new_version_str)) {
            ESP_LOGI(TAG, "New version available: %s (current: %s)", new_version_str.c_str(), current_version.c_str());
            // Set flag that we have a new version available
            new_version_available_ = true;
        } else {
            ESP_LOGI(TAG, "No new version available (current: %s)", current_version.c_str());
            new_version_available_ = false;
        }
    }

    // Check for MQTT configuration
    cJSON *mqtt_config = cJSON_GetObjectItemCaseSensitive(json, "mqtt_config");
    if (cJSON_IsObject(mqtt_config)) {
        // Extract MQTT configuration parameters
        cJSON *mqtt_host = cJSON_GetObjectItemCaseSensitive(mqtt_config, "host");
        cJSON *mqtt_port = cJSON_GetObjectItemCaseSensitive(mqtt_config, "port");
        cJSON *mqtt_username = cJSON_GetObjectItemCaseSensitive(mqtt_config, "username");
        cJSON *mqtt_password = cJSON_GetObjectItemCaseSensitive(mqtt_config, "password");

        if (cJSON_IsString(mqtt_host) && mqtt_host->valuestring != NULL) {
            mqtt_host_ = std::string(mqtt_host->valuestring);
        }
        if (cJSON_IsNumber(mqtt_port)) {
            mqtt_port_ = mqtt_port->valueint;
        }
        if (cJSON_IsString(mqtt_username) && mqtt_username->valuestring != NULL) {
            mqtt_username_ = std::string(mqtt_username->valuestring);
        }
        if (cJSON_IsString(mqtt_password) && mqtt_password->valuestring != NULL) {
            mqtt_password_ = std::string(mqtt_password->valuestring);
        }

        ESP_LOGI(TAG, "MQTT config updated");
    }

    // Check for force update flag
    cJSON *force_update = cJSON_GetObjectItemCaseSensitive(json, "force_update");
    if (cJSON_IsBool(force_update)) {
        force_update_ = cJSON_IsTrue(force_update);
        ESP_LOGI(TAG, "Force update flag: %s", force_update_ ? "true" : "false");
    }

    cJSON_Delete(json);
    return ESP_OK;
}

