void Ota::MarkCurrentVersionValid() {
    ESP_LOGI(TAG, "Marking current version as valid");

    // Get the currently running partition
    const esp_partition_t* running_partition = esp_ota_get_running_partition();
    if (running_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    ESP_LOGI(TAG, "Running partition label: %s, address: 0x%lx", 
             running_partition->label ? running_partition->label : "unknown", 
             running_partition->address);

    // Skip validation for factory partition (typically labeled as "factory" or similar)
    if (running_partition->label && strcmp(running_partition->label, "factory") == 0) {
        ESP_LOGI(TAG, "Skipping validation for factory partition");
        return;
    }

    // Check if the current partition is in a pending verification state
    // We can do this by checking if it's marked as pending
    esp_ota_img_states_t image_state;
    esp_err_t err = esp_ota_get_state_partition(running_partition, &image_state);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Failed to get partition state: %s", esp_err_to_name(err));
        return;
    }

    ESP_LOGI(TAG, "Partition state: %d", image_state);

    // Only mark as valid if it's in PENDING state
    if (image_state == ESP_OTA_IMG_STATE_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Marking partition %s as valid", running_partition->label ? running_partition->label : "unknown");

        // Mark the current running partition as valid
        err = esp_ota_mark_app_valid_cancel_invalid(running_partition);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mark partition as valid: %s", esp_err_to_name(err));
            return;
        }

        ESP_LOGI(TAG, "Successfully marked current version as valid");
    } else if (image_state == ESP_OTA_IMG_STATE_VALID) {
        ESP_LOGI(TAG, "Partition is already marked as valid");
    } else if (image_state == ESP_OTA_IMG_STATE_INVALID) {
        ESP_LOGI(TAG, "Partition is invalid, skipping validation");
    } else {
        ESP_LOGI(TAG, "Partition state is %d, no action taken", image_state);
    }
}

