bool Ota::Upgrade(const std::string& firmware_url, std::function<void(int progress, size_t speed)> callback) {
    ESP_LOGI(TAG, "Starting firmware upgrade from %s", firmware_url.c_str());

    // Create HTTP client
    auto http = SetupHttp();

    // Open connection to firmware URL
    if (!http->Open("GET", firmware_url)) {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for firmware download, code=0x%x", last_error);
        return false;
    }

    // Get content length for progress tracking
    auto content_length = http->GetContentLength();
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Failed to get content length");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Firmware size: %zu bytes", content_length);

    // Find the OTA partition to write to
    const esp_partition_t* ota_partition = esp_ota_get_next_update_partition(NULL);
    if (ota_partition == NULL) {
        ESP_LOGE(TAG, "Failed to find OTA partition");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Writing firmware to partition: %s", ota_partition->label);

    // Start OTA update
    esp_ota_handle_t ota_handle;
    esp_err_t err = esp_ota_begin(ota_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed, error=%s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    // Download and write firmware
    std::vector<uint8_t> buffer(4096);
    size_t downloaded_bytes = 0;
    size_t last_reported_bytes = 0;
    auto start_time = std::chrono::steady_clock::now();

    while (downloaded_bytes < content_length) {
        // Calculate how much to read
        size_t to_read = std::min(buffer.size(), content_length - downloaded_bytes);

        // Read data
        ssize_t bytes_read = http->Read(buffer.data(), to_read);
        if (bytes_read <= 0) {
            ESP_LOGE(TAG, "Failed to read from HTTP connection, bytes_read=%zd", bytes_read);
            esp_ota_end(ota_handle);
            http->Close();
            return false;
        }

        // Write to OTA partition
        err = esp_ota_write(ota_handle, buffer.data(), bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed, error=%s", esp_err_to_name(err));
            esp_ota_end(ota_handle);
            http->Close();
            return false;
        }

        downloaded_bytes += bytes_read;

        // Calculate progress and speed
        int progress = (int)((downloaded_bytes * 100) / content_length);

        // Calculate speed every 100ms
        auto now = std::chrono::steady_clock::now();
        auto elapsed_ms = std::chrono::duration_cast<std::chrono::milliseconds>(now - start_time).count();

        if (elapsed_ms >= 100 || downloaded_bytes == content_length) {
            size_t speed = 0;
            if (elapsed_ms > 0) {
                speed = (downloaded_bytes - last_reported_bytes) * 1000 / elapsed_ms;
            }

            if (callback) {
                callback(progress, speed);
            }

            last_reported_bytes = downloaded_bytes;
            start_time = now;
        }
    }

    // End OTA operation
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed, error=%s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    // Set the new OTA partition as the boot partition
    err = esp_ota_set_boot_partition(ota_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed, error=%s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    http->Close();

    ESP_LOGI(TAG, "Firmware upgrade completed successfully");
    return true;
}

