std::string Ota::GetActivationPayload()
{
    // If no serial number is available, return empty JSON object
    if (!has_serial_number_) {
        return "{}";
    }

    // Create JSON object for activation payload
    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        return "{}";
    }

    // Add serial number
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge
    cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());

    // Generate signature using HMAC-SHA256
    // The signature is computed as: HMAC-SHA256(challenge + serial_number, hardware_key)
    std::string data_to_sign = activation_challenge_ + serial_number_;

#ifdef SOC_HMAC_SUPPORTED
    // Use hardware-backed HMAC functionality
    uint8_t hmac_output[32]; // SHA256 produces 32 bytes

    // Note: This assumes we have access to a hardware key stored in efuse
    // For ESP32, typically the key would be accessed via esp_hmac_calculate
    // However, since we don't see the specific key setup in the constructor,
    // we'll make a reasonable assumption about how to access the key

    // Try to get HMAC key from efuse if available
    esp_err_t err = esp_hmac_calculate(ESP_HMAC_SHA256, 
                                       reinterpret_cast<const uint8_t*>(data_to_sign.c_str()),
                                       data_to_sign.length(),
                                       reinterpret_cast<uint8_t*>(hmac_output),
                                       32);

    if (err == ESP_OK) {
        // Convert HMAC result to hex string for JSON
        std::string signature;
        signature.reserve(64);
        for (int i = 0; i < 32; i++) {
            char hex[3];
            snprintf(hex, sizeof(hex), "%02x", hmac_output[i]);
            signature += hex;
        }
        cJSON_AddStringToObject(root, "signature", signature.c_str());
    } else {
        // If HMAC fails, we still return the payload without signature
        ESP_LOGW(TAG, "Failed to calculate HMAC signature");
    }
#else
    // Fallback when HMAC is not supported
    ESP_LOGW(TAG, "HMAC not supported on this chip");
#endif

    // Convert JSON to string
    char *json_string = cJSON_Print(root);
    std::string result = json_string ? json_string : "{}";

    // Clean up
    cJSON_Delete(root);
    if (json_string) {
        free(json_string);
    }

    return result;
}

