esp_err_t Ota::Activate()
{
    // Check if we have activation challenge and code
    if (!has_activation_challenge_ || !has_activation_code_)
    {
        ESP_LOGE(TAG, "Missing activation challenge or code");
        return ESP_ERR_INVALID_STATE;
    }

    // Construct activation URL
    std::string url = GetCheckVersionUrl();
    if (url.length() < 10)
    {
        ESP_LOGE(TAG, "Activation URL is not properly set");
        return ESP_ERR_INVALID_ARG;
    }

    // Ensure URL ends with activation endpoint
    if (url.back() != '/')
    {
        url += "/";
    }
    url += "activation";

    // Setup HTTP connection
    auto http = SetupHttp();

    // Prepare payload
    std::string payload = GetActivationPayload();
    http->SetContent(payload);

    // Open HTTP POST connection
    if (!http->Open("POST", url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation, code=0x%x", last_error);
        return last_error;
    }

    // Check response status
    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to activate, status code: %d", status_code);
        http->Close();
        return status_code;
    }

    // Read response
    std::string response = http->ReadAll();
    http->Close();

    // Parse response to verify activation success
    cJSON *root = cJSON_Parse(response.c_str());
    if (root == NULL)
    {
        ESP_LOGE(TAG, "Failed to parse activation response JSON");
        return ESP_ERR_INVALID_RESPONSE;
    }

    // Check if activation was successful
    cJSON *success = cJSON_GetObjectItem(root, "success");
    if (cJSON_IsBool(success))
    {
        if (!cJSON_IsTrue(success))
        {
            cJSON_Delete(root);
            ESP_LOGE(TAG, "Activation failed according to server response");
            return ESP_FAIL;
        }
    }
    else
    {
        // If no explicit success field, check if we got a valid response
        cJSON *message = cJSON_GetObjectItem(root, "message");
        if (cJSON_IsString(message))
        {
            ESP_LOGI(TAG, "Activation response: %s", message->valuestring);
        }
    }

    cJSON_Delete(root);

    ESP_LOGI(TAG, "Activation successful");
    return ESP_OK;
}

