void Es8388AudioCodec::SetOutputVolume(int volume) {
    // Store the new volume in internal state
    output_volume_ = volume;

    // Set the hardware volume registers
    // ES8388 volume control registers (HP_LVOL, HP_RVOL, SPK_LVOL, SPK_RVOL)
    uint8_t regs[] = { 46, 47, 48, 49 };
    uint8_t volume_reg_value = static_cast<uint8_t>(volume);

    // Write volume to all four volume registers
    for (uint8_t reg : regs) {
        ctrl_if_->write_reg(ctrl_if_, reg, 1, &volume_reg_value, 1);
    }

    // Also update the software volume setting
    if (output_dev_) {
        ESP_ERROR_CHECK(esp_codec_dev_set_out_vol(output_dev_, volume));
    }
}

