int Es8388AudioCodec::Read(int16_t* dest, int samples) {
    std::lock_guard<std::mutex> lock(data_if_mutex_);

    if (!input_enabled_ || !input_dev_ || dest == nullptr) {
        return 0;
    }

    size_t bytes_read = 0;
    esp_err_t ret = esp_codec_dev_read(input_dev_, dest, samples * sizeof(int16_t), &bytes_read);

    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read audio data, err: %d", ret);
        return 0;
    }

    // Return number of samples read (bytes_read divided by sample size)
    return bytes_read / sizeof(int16_t);
}

