void SetOutputState(uint8_t bit, uint8_t level)
{
    uint8_t data;

    if (bit < 8) {
        // Read current value from register 0x02 (output register for bits 0-7)
        data = ReadReg(0x02);
        // Modify the specific bit
        if (level) {
            data |= (1 << bit);  // Set bit to 1
        } else {
            data &= ~(1 << bit); // Set bit to 0
        }
        // Write back to register 0x02
        WriteReg(0x02, data);
    } else {
        // For bits 8-15, read from register 0x03 (output register for bits 8-15)
        data = ReadReg(0x03);
        // Modify the specific bit (adjust bit number to 0-7 range)
        if (level) {
            data |= (1 << (bit - 8));  // Set bit to 1
        } else {
            data &= ~(1 << (bit - 8)); // Set bit to 0
        }
        // Write back to register 0x03
        WriteReg(0x03, data);
    }
}

