float FrequencyDetector::GetAmplitude() const {
    // If there are fewer than 2 samples in the buffer, return 0
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Get the previous two samples (S[-2] and S[-1])
    float s_minus_2 = state_buffer_.front();  // S[-2]
    float s_minus_1 = *(++state_buffer_.begin());  // S[-1]

    // Apply the Goertzel algorithm to compute real and imaginary components
    // Using the recurrence relation from the ProcessSample method
    float real = s_minus_1 * cos_coefficient_ - s_minus_2;
    float imaginary = s_minus_1 * sin_coefficient_;

    // Calculate amplitude as sqrt(real^2 + imaginary^2)
    float amplitude = std::sqrt(real * real + imaginary * imaginary);

    // Normalize by half the window size as specified in the requirement
    return amplitude / (static_cast<float>(window_size_) * 0.5f);
}

