void Backlight::SetBrightness(uint8_t brightness, bool permanent) {
    // Clamp brightness to valid range [0, 100]
    if (brightness > 100) {
        brightness = 100;
    }

    // Prevent redundant updates if brightness is already set
    if (brightness_ == brightness) {
        return;
    }

    // Store target brightness
    target_brightness_ = brightness;

    // Calculate step size for smooth transition
    // We'll use a simple approach: 10 steps over 100ms total
    const int transition_steps = 10;
    const int transition_time_ms = 100;

    // Calculate step size (positive or negative)
    int diff = target_brightness_ - brightness_;
    step_ = diff > 0 ? (diff + transition_steps - 1) / transition_steps : 
            (diff - transition_steps + 1) / transition_steps;

    // If step is 0, set it to 1 or -1 to ensure progress
    if (step_ == 0) {
        step_ = diff > 0 ? 1 : -1;
    }

    // Start the transition timer if not already running
    if (transition_timer_ != nullptr) {
        esp_timer_start_periodic(transition_timer_, transition_time_ms * 1000);
    }

    // Save to settings if permanent flag is set
    if (permanent) {
        Settings settings("display");
        settings.SetInt("brightness", brightness);
    }
}

