void Backlight::OnTransitionTimer() {
    // Check if we've reached the target brightness
    if (brightness_ == target_brightness_) {
        // Stop the timer since we've reached our target
        if (transition_timer_ != nullptr) {
            esp_timer_stop(transition_timer_);
        }
        return;
    }

    // Calculate new brightness value
    uint8_t new_brightness = brightness_ + step_;

    // Ensure we don't overshoot the target
    if ((step_ > 0 && new_brightness > target_brightness_) || 
        (step_ < 0 && new_brightness < target_brightness_)) {
        new_brightness = target_brightness_;
    }

    // Update the actual brightness
    brightness_ = new_brightness;

    // Apply the new brightness to the hardware
    SetBrightnessImpl(brightness_);

    // If we've reached the target, stop the timer
    if (brightness_ == target_brightness_) {
        if (transition_timer_ != nullptr) {
            esp_timer_stop(transition_timer_);
        }
    }
}

