SingleLed::SingleLed(gpio_num_t gpio) {
    // Configure LED strip parameters
    led_strip_config_t strip_config = {
        .strip_gpio_num = gpio,
        .max_leds = 1, // Single LED
        .led_pixel_format = LED_PIXEL_FORMAT_GRB,
        .led_model = LED_MODEL_WS2812,
        .flags = {
            .output_invert = false,
        },
    };

    // Configure RMT peripheral parameters
    led_strip_rmt_config_t rmt_config = {
        .clk_src = RMT_CLK_SRC_DEFAULT,
        .resolution_hz = 10 * 1000 * 1000, // 10MHz
        .flags = {
            .with_dma = false,
        },
    };

    // Initialize the LED strip
    esp_err_t ret = led_strip_new_rmt_device(&strip_config, &rmt_config, &led_strip_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create LED strip: %s", esp_err_to_name(ret));
        return;
    }

    // Clear the LED initially
    led_strip_clear(led_strip_);

    // Create blink timer
    const esp_timer_create_args_t timer_config = {
        .callback = [](void* arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .name = "led_blink",
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
    };

    ret = esp_timer_create(&timer_config, &blink_timer_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create blink timer: %s", esp_err_to_name(ret));
        return;
    }

    // Initialize color to black (LED off)
    r_ = 0;
    g_ = 0;
    b_ = 0;
}

