std::string MqttProtocol::DecodeHexString(const std::string& hex_string) {
    std::string result;

    // Process the hex string two characters at a time
    for (size_t i = 0; i < hex_string.length(); i += 2) {
        // Make sure we have at least 2 characters left
        if (i + 1 < hex_string.length()) {
            char high = hex_string[i];
            char low = hex_string[i + 1];

            // Convert each hex character to its numeric value and combine them
            uint8_t byte_value = (CharToHex(high) << 4) | CharToHex(low);

            // Append the resulting byte to the result string
            result.push_back(static_cast<char>(byte_value));
        }
    }

    return result;
}

